// ============================================================================
// sync-fixtures.mjs — pull World Cup 2026 fixtures from API-Football and load
// them into Supabase (fixtures + stage-aware markets) via the sync_fixture RPC.
//
// Run:  node sync-fixtures.mjs
//
// Requires three env vars (NEVER hardcode the secret key in client code):
//   API_FOOTBALL_KEY       your api-sports.io key
//   SUPABASE_URL           https://xxxx.supabase.co
//   SUPABASE_SERVICE_KEY   the SECRET key (sb_secret_...) — server-side only
//
// Example:
//   API_FOOTBALL_KEY=xxx \
//   SUPABASE_URL=https://txc...supabase.co \
//   SUPABASE_SERVICE_KEY=sb_secret_xxx \
//   node sync-fixtures.mjs
//
// Node 20+ (uses global fetch). No dependencies.
// ============================================================================

const API_KEY  = process.env.API_FOOTBALL_KEY;
const SB_URL    = process.env.SUPABASE_URL;
const SB_KEY    = process.env.SUPABASE_SERVICE_KEY;
const OPEN_MARKETS = process.env.OPEN_MARKETS === '1'; // default: create LOCKED

if (!API_KEY || !SB_URL || !SB_KEY) {
  console.error('Missing env. Need API_FOOTBALL_KEY, SUPABASE_URL, SUPABASE_SERVICE_KEY.');
  process.exit(1);
}

const AF = 'https://v3.football.api-sports.io';
const afHeaders = { 'x-apisports-key': API_KEY };
const sbHeaders = {
  apikey: SB_KEY,
  Authorization: `Bearer ${SB_KEY}`,
  'Content-Type': 'application/json',
};

// Map API-Football "round" strings to our stage codes.
function roundToStage(round) {
  if (!round) return { stage: 'GROUP', matchday: null };
  const r = round.toLowerCase();
  if (r.startsWith('group')) {
    const m = r.match(/(\d+)/);
    return { stage: 'GROUP', matchday: m ? parseInt(m[1], 10) : null };
  }
  if (r.includes('round of 32')) return { stage: 'R32', matchday: null };
  if (r.includes('round of 16')) return { stage: 'R16', matchday: null };
  if (r.includes('quarter'))     return { stage: 'QF',  matchday: null };
  if (r.includes('semi'))        return { stage: 'SF',  matchday: null };
  if (r.includes('3rd') || r.includes('third')) return { stage: '3P', matchday: null };
  if (r.includes('final'))       return { stage: 'F',   matchday: null };
  return { stage: 'GROUP', matchday: null };
}

async function afGet(path) {
  const res = await fetch(`${AF}${path}`, { headers: afHeaders });
  const json = await res.json();
  if (json.errors && (Array.isArray(json.errors) ? json.errors.length : Object.keys(json.errors).length)) {
    throw new Error('API-Football error: ' + JSON.stringify(json.errors));
  }
  return json.response;
}

async function buildTeamCodeMap() {
  // /teams gives a 3-letter `code` per national team; fall back to name.
  const teams = await afGet('/teams?league=1&season=2026');
  const map = {};
  for (const t of teams) {
    const team = t.team || t;
    map[team.id] = team.code || team.name;
  }
  return map;
}

async function syncOne(fx, codeMap) {
  const api_id   = fx.fixture.id;
  const { stage, matchday } = roundToStage(fx.league.round);
  const codeA = codeMap[fx.teams.home.id] || fx.teams.home.name;
  const codeB = codeMap[fx.teams.away.id] || fx.teams.away.name;
  const kickoff = fx.fixture.date;
  const venue = [fx.fixture.venue?.name, fx.fixture.venue?.city].filter(Boolean).join(', ');

  const res = await fetch(`${SB_URL}/rest/v1/rpc/sync_fixture`, {
    method: 'POST',
    headers: sbHeaders,
    body: JSON.stringify({
      p_api_id: api_id,
      p_stage: stage,
      p_matchday: matchday,
      p_team_a: codeA,
      p_team_b: codeB,
      p_kickoff: kickoff,
      p_venue: venue,
      p_open: OPEN_MARKETS,
    }),
  });
  if (!res.ok) {
    const txt = await res.text();
    throw new Error(`sync_fixture failed for ${api_id}: ${res.status} ${txt.slice(0, 200)}`);
  }
  const fid = (await res.json());
  return { fid, stage, matchday, codeA, codeB };
}

async function main() {
  console.log('→ Building team code map…');
  const codeMap = await buildTeamCodeMap();
  console.log(`  ${Object.keys(codeMap).length} teams mapped.`);

  console.log('→ Fetching fixtures (league=1, season=2026)…');
  const fixtures = await afGet('/fixtures?league=1&season=2026');
  console.log(`  ${fixtures.length} fixtures returned.`);

  let ok = 0, fail = 0;
  const byStage = {};
  for (const fx of fixtures) {
    try {
      const r = await syncOne(fx, codeMap);
      byStage[r.stage] = (byStage[r.stage] || 0) + 1;
      ok++;
      process.stdout.write('.');
    } catch (e) {
      fail++;
      console.error(`\n  ✗ ${fx.fixture?.id}: ${e.message}`);
    }
  }
  console.log(`\nSynced ${ok} fixtures (${fail} failed).`);
  console.log('   By stage:', JSON.stringify(byStage));
  console.log(OPEN_MARKETS
    ? '   Markets created OPEN.'
    : '   Markets created LOCKED. Open them when ready via admin_open_all_markets() or per group.');
}

main().catch(e => { console.error('FATAL:', e.message); process.exit(1); });
